package com.example.rest_kafka_poc.config;import org.apache.kafka.clients.consumer.ConsumerConfig;import org.apache.kafka.clients.consumer.ConsumerRecord;import org.apache.kafka.common.serialization.StringDeserializer;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.kafka.annotation.EnableKafka;import org.springframework.kafka.core.ConsumerFactory;import org.springframework.kafka.core.DefaultKafkaConsumerFactory;import org.springframework.kafka.listener.ConcurrentMessageListenerContainer;import org.springframework.kafka.listener.ContainerProperties;import org.springframework.kafka.listener.MessageListener;import java.util.HashMap;import java.util.Map;@Configuration@EnableKafkapublic class Kafka_ConsumerConfig {    private static final String BOOTSTRAP_SERVERS = "localhost:29092";    private static final String GROUP_ID = "my-group";    private static final String TOPIC = "my-topic";    @Bean    public ConsumerFactory<String, String> consumerFactory() {        Map<String, Object> configProps = new HashMap<>();        configProps.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, BOOTSTRAP_SERVERS);        configProps.put(ConsumerConfig.GROUP_ID_CONFIG, GROUP_ID);        configProps.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);        configProps.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);        return new DefaultKafkaConsumerFactory<>(configProps);    }    @Bean    public ConcurrentMessageListenerContainer<String, String> messageListenerContainer() {        ContainerProperties containerProps = new ContainerProperties(TOPIC);        containerProps.setMessageListener(new MessageListener<String, String>() {            @Override            public void onMessage(ConsumerRecord<String, String> record) {                System.out.println("Received message: " + record.value());            }        });        return new ConcurrentMessageListenerContainer<>(consumerFactory(), containerProps);    }}